input.query:
let webservers = dynamic(['w3wp.exe', 'httpd.exe', 'nginx.exe', 'owstimer.exe', 'visualsvnserver.exe']);
let windowsShells = dynamic(['powershell.exe', 'powershell_ise.exe', 'cmd.exe']);
let exclusions = dynamic(['csc.exe', 'php-cgi.exe', 'vbc.exe', 'conhost.exe']);
DeviceProcessEvents
| where InitiatingProcessParentFileName in~ (webservers) or InitiatingProcessCommandLine has_any (webservers)
| where InitiatingProcessFileName in~ (windowsShells)
| where FileName !in~ (exclusions)
| extend Reason = iff(InitiatingProcessParentFileName in~ (webservers), 'Suspicious web shell execution', 'Suspicious webserver process')
| summarize TotalEvents = count() by FileName, DeviceId, DeviceName, Reason, InitiatingProcessParentFileName, InitiatingProcessCommandLine
